package base
import ccxt "github.com/ccxt/ccxt/go/v4"

// PLEASE DO NOT EDIT THIS FILE, IT IS GENERATED AND WILL BE OVERWRITTEN:
// https://github.com/ccxt/ccxt/blob/master/CONTRIBUTING.md#how-to-contribute-code

func TestBinaryToBase16()  {
    exchange := ccxt.NewExchange().(*ccxt.Exchange); exchange.DerivedExchange = exchange; exchange.InitParent(map[string]interface{} {
        "id": "sampleexchange",
    }, map[string]interface{}{}, exchange)
    assert(ccxt.IsEqual(exchange.ParseNumber(nil), nil), "GO_WORKAROUND")
    // @SKIP_START_GO
    // Test 1: simple known bytes
    // 'ff' => [255]
    var binary1 interface{} = exchange.Base16ToBinary("ff")
    Assert(ccxt.IsEqual(exchange.BinaryToBase16(binary1), "ff"))
    // Test 2: all zeros
    // '0000' => [0, 0]
    var binary2 interface{} = exchange.Base16ToBinary("0000")
    Assert(ccxt.IsEqual(exchange.BinaryToBase16(binary2), "0000"))
    // Test 3: ascending bytes 01 02 03 04
    var binary3 interface{} = exchange.Base16ToBinary("01020304")
    Assert(ccxt.IsEqual(exchange.BinaryToBase16(binary3), "01020304"))
    // Test 4: single byte zero
    var binary4 interface{} = exchange.Base16ToBinary("00")
    Assert(ccxt.IsEqual(exchange.BinaryToBase16(binary4), "00"))
    // Test 5: single byte max
    var binary5 interface{} = exchange.Base16ToBinary("ff")
    Assert(ccxt.IsEqual(exchange.BinaryLength(binary5), 1))
    Assert(exchange.IsBinaryMessage(binary5))
    // Test 6: 8 bytes (like a timestamp encoding)
    // 00 00 00 00 49 96 02 d2 = 1234567890
    var binary6 interface{} = exchange.Base16ToBinary("00000000499602d2")
    Assert(ccxt.IsEqual(exchange.BinaryToBase16(binary6), "00000000499602d2"))
    Assert(ccxt.IsEqual(exchange.BinaryLength(binary6), 8))
    // Test 7: roundtrip with deadbeef
    var binary7 interface{} = exchange.Base16ToBinary("deadbeef")
    Assert(ccxt.IsEqual(exchange.BinaryToBase16(binary7), "deadbeef"))
    Assert(ccxt.IsEqual(exchange.BinaryLength(binary7), 4))
    // Test 8: roundtrip binaryToBase16 -> base16ToBinary
    var hex8 interface{} = "cafebabe"
    var binary8 interface{} = exchange.Base16ToBinary(hex8)
    Assert(ccxt.IsEqual(exchange.BinaryToBase16(binary8), hex8))
}